import{n as e,t}from"./en-BeAvWqrp.js";import{t as n}from"./merge-9Qs9NaoX.js";var r=n(t,{auth:{nav:{signIn:`Inloggen`,createAccount:`Account aanmaken`,mobileTagline:`Eén naadloze copier voor elk Telegram-signaal`,backHome:`Terug naar home`},oauth:{continueWithGoogle:`Doorgaan met Google`,orDivider:`of`},login:{heading:`Inloggen bij TScopier`,noAccount:`Nog geen account?`,signUpLink:`Registreren`,footerPrompt:`Nieuw bij TScopier?`,footerLink:`Maak een gratis account`,email:`E-mail`,emailPlaceholder:`jij@voorbeeld.nl`,password:`Wachtwoord`,passwordPlaceholder:`Voer je wachtwoord in`,forgotPassword:`Wachtwoord vergeten?`,passwordResetSuccess:`Je wachtwoord is bijgewerkt. Je kunt nu inloggen.`,submit:`Inloggen`},forgotPassword:{heading:`Wachtwoord resetten`,subtitle:`Voer het e-mailadres van je account in. Als het bestaat, sturen we een link om je wachtwoord te resetten.`,email:`E-mail`,emailPlaceholder:`jij@voorbeeld.nl`,submit:`Resetlink versturen`,sentHeading:`Controleer je e-mail`,sentSubtitle:`Als er een account bestaat voor {email}, ontvang je binnenkort een resetlink.`,sentHint:`Controleer je spammap als je het bericht niet binnen enkele minuten ziet.`,backToLogin:`Terug naar inloggen`},resetPassword:{heading:`Kies een nieuw wachtwoord`,subtitle:`Voer hieronder je nieuwe wachtwoord in en bevestig het.`,password:`Nieuw wachtwoord`,passwordPlaceholder:`Voer een nieuw wachtwoord in`,confirmPassword:`Bevestig wachtwoord`,confirmPasswordPlaceholder:`Voer je nieuwe wachtwoord opnieuw in`,passwordHint:`Minimaal 6 tekens`,passwordTooShort:`Wachtwoord moet minimaal 6 tekens bevatten`,passwordMismatch:`Wachtwoorden komen niet overeen`,submit:`Wachtwoord bijwerken`,invalidHeading:`Link verlopen of ongeldig`,invalidSubtitle:`Deze resetlink is niet meer geldig. Vraag een nieuwe aan om door te gaan.`,requestNewLink:`Nieuwe link aanvragen`,backToLogin:`Terug naar inloggen`},signup:{heading:`Maak je account`,hasAccount:`Heb je al een account?`,signInLink:`Inloggen`,footerPrompt:`Heb je al een account?`,footerLink:`Inloggen`,firstName:`Voornaam`,firstNamePlaceholder:`Voornaam`,lastName:`Achternaam`,lastNamePlaceholder:`Achternaam`,email:`E-mail`,emailPlaceholder:`jij@voorbeeld.nl`,password:`Wachtwoord`,passwordPlaceholder:`Kies een wachtwoord`,confirmPassword:`Bevestig wachtwoord`,confirmPasswordPlaceholder:`Voer je wachtwoord opnieuw in`,passwordHint:`Minimaal 6 tekens`,passwordTooShort:`Wachtwoord moet minimaal 6 tekens bevatten`,passwordMismatch:`Wachtwoorden komen niet overeen`,submit:`Account aanmaken`,terms:{prefix:`Door je te registreren ga je akkoord met onze`,termsOfService:`Servicevoorwaarden`,conjunction:` en `,privacyPolicy:`Privacybeleid`}},verify:{heading:`Controleer je e-mail`,subtitle:`We hebben zojuist een verificatielink gestuurd naar {email}.`,resend:`E-mail opnieuw versturen`,resent:`E-mail verzonden!`,backToLogin:`Terug naar inloggen`},marketing:{headline:`Eén naadloze copier voor elk Telegram-signaal`,trustpilotLabel:`Trustpilot`,reviews:e,copyright:`© {year} Tartarix Inc.`},language:{label:`Taal`,choose:`Kies taal`,searchPlaceholder:`Talen zoeken…`,noResults:`Geen talen gevonden`},theme:{light:`Lichte modus`,dark:`Donkere modus`,switchToLight:`Schakel naar lichte modus`,switchToDark:`Schakel naar donkere modus`}},contactSupportPage:{channelsTitle:`Hoe kunnen we je helpen?`,channelsSubtitle:`Neem contact op met het TSCopier-team via e-mail, bekijk de documentatie of start een livechat.`,email:{title:`E-mailondersteuning`,description:`Stuur vragen over account, facturatie of copier - we reageren meestal binnen een werkdag.`,cta:`Support e-mailen`},docs:{title:`Documentatie`,description:`Stapsgewijze handleidingen voor het koppelen van brokers, Telegram-kanalen, handelsstijlen en probleemoplossing.`,cta:`Documentatie openen`},liveChat:{title:`Livechat`,description:`Chat in realtime met ons voor snelle hulp bij de setup terwijl je in het dashboard werkt.`,cta:`Livechat starten`},faq:{title:`Veelgestelde vragen`,subtitle:`Snelle antwoorden voordat je contact opneemt.`,items:[{question:`Hoe koppel ik mijn MetaTrader-account?`,answer:`Open Configuratie, voeg een brokeraccount toe, voer je MetaTrader-inloggegevens in en wacht tot de verbindingsstatus op verbonden staat. Voor elk gekoppeld account moeten handelsstijl, lotgrootte en kanaalselectie zijn opgeslagen voordat het kopiëren start.`},{question:`Waarom worden mijn Telegram-signalen niet gekopieerd?`,answer:`Controleer of je broker is verbonden, het Telegram-kanaal is gekoppeld en actief is, het kanaal bij de broker in Configuratie is geselecteerd, je abonnement actief is en je e-mailadres is geverifieerd. Controleer Copier Logs op redenen voor overslaan, zoals kanaalfilters, nieuwsblackout of ontbrekende SL/TP in het signaal.`},{question:`Hoe voeg ik een Telegram-signaalkanaal toe?`,answer:`Ga naar Kanalen, koppel Telegram indien nodig en voeg daarna de kanaalgebruikersnaam of uitnodigingslink toe. Activeer het kanaal en wijs het in Configuratie toe aan de brokeraccounts die de signalen moeten kopiëren.`},{question:`Wat doet nieuwshandel / economische-kalender-blackout?`,answer:`Wanneer nieuwshandel op een account is uitgeschakeld, kan TSCopier nieuwe posities pauzeren en optioneel open transacties sluiten rond kalendergebeurtenissen met hoge impact. Gebruik de pagina Economische kalender om komende publicaties te zien en regels in te stellen onder Accountconfiguratie.`},{question:`Heb ik een betaald abonnement nodig om transacties te kopiëren?`,answer:`Een actief betaald plan is vereist voor live uitvoering van de Telegram-copier. Je kunt het dashboard en de configuratie nog steeds verkennen in een beschikbare proefperiode; controleer Facturatie voor je huidige plan en verlengingsstatus.`},{question:`Waarom moet ik mijn e-mailadres verifiëren voordat ik het platform gebruik?`,answer:`E-mailverificatie bevestigt je login en stelt ons in staat factuurbewijzen en belangrijke accountmeldingen te sturen. Als je vastloopt op het verificatiescherm, gebruik dan de link om opnieuw te verzenden of neem contact op met support met het adres waarmee je je hebt geregistreerd.`},{question:`Mijn broker staat als niet verbonden - wat kan ik proberen?`,answer:`Controleer of MetaTrader aan de brokerkant draait, je inloggegevens nog geldig zijn en het account niet is vergrendeld. Vernieuw vanuit Configuratie en controleer daarna Copier Logs op sessiefouten. Als het probleem aanhoudt, mail support met je brokernaam en accountlogin (nooit je wachtwoord).`},{question:`Kan ik hetzelfde kanaal naar meerdere brokers kopiëren?`,answer:`Ja. Koppel elk MetaTrader-account afzonderlijk in Configuratie en selecteer hetzelfde Telegram-kanaal voor elke broker. Lotgrootte, handelsstijl en risicoinstellingen worden per account ingesteld.`}]}},riskDisclaimerPage:{title:`Risicowaarschuwing`,intro:`Handelen in forex, CFD's en andere producten met hefboomwerking brengt een aanzienlijk risico op verlies met zich mee. TSCopier is een tool voor het kopieren van transacties — geen broker, beleggingsadviseur of financieel planner. Niets op deze pagina is financieel advies. U bent zelf volledig verantwoordelijk voor uw handelsbeslissingen en eventuele verliezen.`,sections:[{title:`Algemeen handelsrisico`,paragraphs:[`U kunt een deel of al uw ingelegde kapitaal verliezen. Hefboomwerking vergroot zowel winsten als verliezen. Eerdere prestaties van een signaalaanbieder, backtest of uw eigen historie bieden geen garantie voor toekomstige resultaten.`,`Markten kunnen met gaps openen, stilvallen of extreem bewegen tijdens nieuwsgebeurtenissen. TSCopier garandeert niet dat signalen op een bepaald moment of tegen een bepaalde prijs worden ontvangen, geparseerd of uitgevoerd.`]},{title:`Risico van signaalaanbieders`,paragraphs:[`Kopieer alleen signaalaanbieders die u vertrouwt en begrijpt. Aanbieders kunnen prikkels hebben die botsen met uw belangen. Marketing-screenshots, claims over winrates en geselecteerde resultaten weerspiegelen mogelijk niet wat u ervaart op uw account, met uw lotgrootte, broker of latency.`,`Controleer prestaties waar mogelijk onafhankelijk. Een aanbieder die voor anderen werkt, kan nog steeds ongeschikt zijn voor uw risicotolerantie, accountgrootte of handelstijden.`]},{title:`Repainting en kanaalmanipulatie`,paragraphs:[`Sommige Telegram-signaalkanalen bewerken of verwijderen berichten nadat een trade misgaat, zodat de publieke feed foutloos lijkt. Een "succesvolle" call kan zijn aangepast; een verliezende call kan volledig verdwijnen.`,`Vertrouw niet alleen op de zichtbare kanaalgeschiedenis of screenshots van derden. Vergelijk met uw eigen Copier Logs, brokerafschriften en records met tijdstempel. Repainting maakt het voor aanbieders eenvoudig om nauwkeuriger te lijken dan ze in werkelijkheid zijn.`]},{title:`Beperkingen in parsing en uitvoering`,paragraphs:[`Signalen worden automatisch uit tekst geinterpreteerd. Typefouten in stop loss (SL) of take profit (TP) — verkeerde cijfers, ontbrekende decimalen, dubbelzinnige symbolen of gemengde eenheden — kunnen ongeldige prijzen veroorzaken. TSCopier kan het signaal overslaan, ongeldige niveaus negeren of standaardwaarden uit uw configuratie toepassen in plaats van de bedoeling van de aanbieder.`,`De uitvoering kan afwijken van de entry van de aanbieder: slippage, requotes, gedeeltelijke fills, regels voor minimale afstand en verbroken brokersessies beinvloeden de uitkomst. Strict entry-, range pending- en multi-leg-stijlen voegen extra complexiteit toe. Controleer open posities altijd bij uw broker.`]},{title:`Operationele en configuratierisico's`,paragraphs:[`Nieuwsblack-outs, kanaalfilters, winstdoelen, limieten voor maximaal verlies, abonnementsstatus en instellingen per kanaal kunnen kopieren blokkeren of wijzigen. Verkeerd ingestelde lotgrootte, symboolmapping of niet-gekoppelde kanalen zijn veelvoorkomende redenen waarom trades niet worden gekopieerd zoals verwacht.`,`Automatisch sluiten wanneer limieten worden geraakt, sluit kanaaltoegeschreven trades aan de TSCopier-kant, maar kan reeds geleden marktverlies niet ongedaan maken. Configuratiewijzigingen worden pas actief na opslaan — niet-opgeslagen concepten beschermen uw account niet.`]},{title:`Blijf betrokken tijdens kopieren`,paragraphs:[`Automatisch kopieren is geen "instellen en vergeten". Controleer open trades, equity, margin en Copier Logs regelmatig. Grijp in bij uw broker wanneer omstandigheden veranderen of wanneer u het niet langer eens bent met de blootstelling van de aanbieder.`,`Als u uw account niet actief kunt monitoren, kan het kopieren van live signalen ongeschikt voor u zijn.`]},{title:`Uw kansen verbeteren (geen advies)`,paragraphs:[`Begin met een demo-account of met de kleinste live omvang die u zich kunt veroorloven te verliezen. Beoordeel kanalen over langere tijd; gebruik backtests waar beschikbaar; activeer limieten voor maximaal verlies en winstdoelen; verfijn kanaalfilters; spreid over aanbieders in plaats van risico te concentreren.`,`Lees de skip-redenen in Copier Logs wanneer signalen niet worden verhandeld. Houd realistische verwachtingen — consistente kleine voordelen met strikte risicocontrole verschillen sterk van "snel rijk worden"-marketing.`]}],closing:`Door TSCopier te gebruiken erkent u dat handelen risicovol is, dat signaalaanbieders onbetrouwbaar of misleidend kunnen zijn, en dat u de volledige verantwoordelijkheid aanvaardt voor alle trades die op uw gekoppelde accounts worden geplaatst.`}});export{r as nl};